// Primitive union
type ID = string | number;
let id: ID = 'abc-123'; // string — OK
id = 42;                 // number — OK
// id = true;           // TS2322 — boolean is not assignable

// Function parameter accepting multiple types
function formatId(id: string | number): string {
  return String(id).padStart(8, '0');
}
formatId('abc');   // OK
formatId(123);     // OK

// Return type union
function maybeGet(key: string): string | undefined {
  const map: Record<string, string> = { a: 'alpha' };
  return map[key]; // string | undefined
}

// Nullable type — common pattern
type NullableString = string | null;
let name: NullableString = 'Alice';
name = null; // OK
// name.toLowerCase(); // TS2531 — Object is possibly null

// Union with literal types
type Direction = 'north' | 'south' | 'east' | 'west';
type HttpMethod = 'GET' | 'POST' | 'PUT' | 'DELETE' | 'PATCH';
type Port = 80 | 443 | 3000 | 8080;

function display(value: string | number): string {
  // value.toUpperCase(); // TS2339 — not on number
  // value.toFixed(2);    // TS2339 — not on string

  // typeof narrows to a specific branch
  if (typeof value === 'string') {
    return value.toUpperCase(); // value: string
  }
  return value.toFixed(2);      // value: number
}

// Object union — narrowed with discriminant property
type Circle    = { kind: 'circle';    radius: number };
type Rectangle = { kind: 'rectangle'; width: number; height: number };
type Shape     = Circle | Rectangle;

function area(shape: Shape): number {
  switch (shape.kind) {
    case 'circle':    return Math.PI * shape.radius ** 2;
    case 'rectangle': return shape.width * shape.height;
  }
}

// Union over objects without discriminant
interface Cat { name: string; purr(): void }
interface Dog { name: string; bark(): void }
type Pet = Cat | Dog;

function greetPet(pet: Pet): void {
  console.log(pet.name); // name exists on both — no narrowing needed

  // 'bark' not accessible without narrowing
  if ('bark' in pet) {
    pet.bark(); // pet: Dog
  } else {
    pet.purr(); // pet: Cat
  }
}

// Each variant has kind as its discriminant
type LoadingState = { kind: 'loading' };
type SuccessState = { kind: 'success'; data: string[] };
type ErrorState   = { kind: 'error';   message: string };
type AsyncState   = LoadingState | SuccessState | ErrorState;

function assertNever(x: never): never {
  throw new Error('Unhandled: ' + JSON.stringify(x));
}

function renderState(state: AsyncState): string {
  switch (state.kind) {
    case 'loading': return 'Loading…';
    case 'success': return state.data.join(', ');  // state: SuccessState
    case 'error':   return 'Error: ' + state.message; // state: ErrorState
    default:        return assertNever(state); // exhaustiveness check
  }
}

// Adding a new variant without handling it triggers TS2345 on assertNever
type AsyncStateV2 = AsyncState | { kind: 'cancelled' };
// Adding the case: is required by the compiler

// Combining two object types
interface HasName { name: string }
interface HasAge  { age: number }

type Person = HasName & HasAge;

const p: Person = { name: 'Alice', age: 30 }; // must have both
// const bad: Person = { name: 'Bob' }; // TS2322 — missing age

// Intersection of three interfaces
interface Serialisable { serialize(): string }
interface Loggable     { log(): void }
interface Validatable  { isValid(): boolean }

type StrictModel = HasName & Serialisable & Loggable & Validatable;

// Primitive intersections — often reduce to never
type StringAndNumber = string & number; // never — no value is both
// Primitive intersections are only meaningful in conditional type distributions

// Extending a third-party or generated type
interface ApiUser {
  id: number;
  email: string;
}

// Add client-side fields without modifying ApiUser
type LocalUser = ApiUser & {
  displayName: string;
  lastSeen: Date;
};

const user: LocalUser = {
  id: 1,
  email: 'alice@example.com',
  displayName: 'Alice',
  lastSeen: new Date(),
};

// Mixin pattern — compose behaviour from separate interfaces
interface WithTimestamps {
  createdAt: Date;
  updatedAt: Date;
}

type AuditedUser = ApiUser & WithTimestamps;

// Angular: extending HttpParams-like options
interface BaseRequestOptions {
  headers?: Record<string, string>;
  withCredentials?: boolean;
}

type AuthenticatedOptions = BaseRequestOptions & {
  authToken: string;
};

// Compatible overlapping property
interface A { x: number }
interface B { x: number; y: string }
type AB = A & B;
// x: number (number & number = number), y: string

// Incompatible overlapping property
interface C { x: string }
type AC = A & C;
// x: string & number = never

// Attempting to assign to x fails
// const obj: AC = { x: 'hello' }; // TS2322 — string is not assignable to never
// const obj: AC = { x: 42 };      // TS2322 — number is not assignable to never
// The type AC is technically valid but has no assignable values for x

// Method intersection — both signatures must be satisfied
interface Readable  { read():  string }
interface Writeable { write(s: string): void }
type ReadWrite = Readable & Writeable;

class Buffer implements ReadWrite {
  private data = '';
  read()  { return this.data; }
  write(s: string) { this.data += s; }
}

import { signal } from '@angular/core';

type FetchState<T> =
  | { status: 'idle' }
  | { status: 'loading' }
  | { status: 'success'; data: T }
  | { status: 'error';   error: string };

@Component({
  selector: 'app-user-list',
  template: `
    @switch (state().status) {
      @case ('loading') { <spinner /> }
      @case ('success') { <ul> @for (u of state().data; track u.id) { <li>{{ u.name }}</li> } </ul> }
      @case ('error')   { <p class="error">{{ state().error }}</p> }
      @default           { <p>Press load to begin.</p> }
    }
  `,
})
class UserListComponent {
  state = signal<FetchState<User[]>>({ status: 'idle' });

  async load(): Promise<void> {
    this.state.set({ status: 'loading' });
    try {
      const data = await fetchUsers();
      this.state.set({ status: 'success', data });
    } catch (e) {
      this.state.set({ status: 'error', error: String(e) });
    }
  }
}

import { ActivatedRouteSnapshot } from '@angular/router';

interface AuthenticatedRoute {
  userId: string;
}

interface PaginatedRoute {
  page: number;
  limit: number;
}

// Route data that is both authenticated and paginated
type AdminListRoute = ActivatedRouteSnapshot & {
  data: AuthenticatedRoute & PaginatedRoute;
};

// Angular service with mixin-style interface composition
interface Cacheable {
  clearCache(): void;
  getCacheKey(): string;
}

interface Refreshable {
  refresh(): Promise<void>;
}

// A service that is both cacheable and refreshable
type ManagedService = Cacheable & Refreshable;

@Injectable({ providedIn: 'root' })
class ProductService implements ManagedService {
  private cache = new Map<string, unknown>();

  clearCache(): void { this.cache.clear(); }
  getCacheKey(): string { return 'products'; }

  async refresh(): Promise<void> {
    this.clearCache();
    // re-fetch data
  }
}

// NonNullable — removes null and undefined from a union
type MaybeUser = User | null | undefined;
type DefiniteUser = NonNullable<MaybeUser>; // User

// Partial — makes all properties optional (uses mapped type + union with undefined)
type PartialUser = Partial<User>; // { id?: number; name?: string }

// Required — opposite of Partial
type RequiredUser = Required<PartialUser>; // { id: number; name: string }

// Pick / Omit — create subsets
interface Product { id: number; name: string; price: number; stock: number }
type ProductSummary = Pick<Product, 'id' | 'name'>;          // { id, name }
type ProductNoStock = Omit<Product, 'stock'>;                  // { id, name, price }

// Record — maps keys to a type
type RoleMap = Record<'admin' | 'user' | 'guest', string[]>;
const roles: RoleMap = {
  admin: ['read', 'write', 'delete'],
  user:  ['read', 'write'],
  guest: ['read'],
};

// Extract / Exclude — filter union members
type Numeric = Extract<string | number | boolean, number>; // number
type Strings = Exclude<string | number | boolean, number>; // string | boolean

// Without distribution — single type check
type IsString<T> = T extends string ? 'yes' : 'no';
type R1 = IsString<string>;          // 'yes'
type R2 = IsString<number>;          // 'no'

// With a union — TypeScript distributes automatically
type R3 = IsString<string | number>; // 'yes' | 'no'
// This is equivalent to:
// IsString<string> | IsString<number>
// = 'yes' | 'no'

// Exclude built on distributive conditional types
type Exclude<T, U> = T extends U ? never : T;
type NotString = Exclude<string | number | boolean, string>;
// string extends string → never
// number extends string → number
// boolean extends string → boolean
// Result: number | boolean

// Extract — keep members that extend U
type Extract<T, U> = T extends U ? T : never;
type OnlyString = Extract<string | number | boolean, string | boolean>;
// string → string, number → never, boolean → boolean
// Result: string | boolean

// Prevent distribution — wrap in a tuple
type IsStringExact<T> = [T] extends [string] ? 'yes' : 'no';
type R4 = IsStringExact<string | number>; // 'no' — union checked as-is, not distributed

type Size   = 'sm' | 'md' | 'lg';
type Color  = 'red' | 'blue' | 'green';

// Cross-product of all combinations
type ButtonVariant = `btn-${Size}-${Color}`;
// 'btn-sm-red' | 'btn-sm-blue' | 'btn-sm-green'
// | 'btn-md-red' | 'btn-md-blue' | 'btn-md-green'
// | 'btn-lg-red' | 'btn-lg-blue' | 'btn-lg-green'

// Angular CSS class utility
type Spacing  = 'none' | 'sm' | 'md' | 'lg' | 'xl';
type Direction = 'top' | 'right' | 'bottom' | 'left' | 'x' | 'y';
type PaddingClass = `p${Direction extends string ? Direction : never}-${Spacing}`;

// Event listener names generated from a union
type EventName = 'click' | 'keydown' | 'scroll';
type ListenerName = `on${Capitalize<EventName>}`;
// 'onClick' | 'onKeydown' | 'onScroll'

// Binary tree node — recursive union
type TreeNode<T> =
  | { kind: 'leaf'; value: T }
  | { kind: 'branch'; left: TreeNode<T>; right: TreeNode<T> };

function sumTree(node: TreeNode<number>): number {
  if (node.kind === 'leaf') return node.value;
  return sumTree(node.left) + sumTree(node.right);
}

const tree: TreeNode<number> = {
  kind: 'branch',
  left:  { kind: 'leaf', value: 1 },
  right: {
    kind: 'branch',
    left:  { kind: 'leaf', value: 2 },
    right: { kind: 'leaf', value: 3 },
  },
};

console.log(sumTree(tree)); // 6

// JSON-like recursive type (not using any)
type JsonValue =
  | string
  | number
  | boolean
  | null
  | JsonValue[]
  | { [key: string]: JsonValue };

const config: JsonValue = {
  name: 'app',
  debug: false,
  ports: [3000, 8080],
  db: { host: 'localhost', port: 5432 },
};

interface Point2D { x: number; y: number }
interface WithZ   { z: number }

// Type intersection
type Point3D = Point2D & WithZ;

// Value construction — object spread creates the combined shape
function addZ(p: Point2D, z: number): Point3D {
  return { ...p, z }; // satisfies Point3D
}

const p3 = addZ({ x: 1, y: 2 }, 3);
// p3: Point3D — has x, y, z

// Type cast is not needed — the spread value already satisfies the intersection

